    Arrays.sort(costs, (a, b) -> (a[0] - a[1]) - (b[0] - b[1]));

    int totalCost = 0;
    int n = costs.length / 2;

    for (int i = 0; i < n; i++) {
        totalCost += costs[i][0] + costs[i + n][1];
    }

    return totalCost;
}
```

